import React from 'react';
import { X, Globe, Highlighter, Type, AlignJustify, MoveHorizontal, Settings as SettingsIcon } from 'lucide-react';
import { AppSettings, ThemeColor } from '../types';

interface Props {
  isOpen: boolean;
  onClose: () => void;
  settings: AppSettings;
  onUpdate: (newSettings: AppSettings) => void;
}

const COLORS: { id: ThemeColor; label: string; class: string }[] = [
  { id: 'indigo', label: 'Neon Indigo', class: 'bg-[#00f3ff]' },
  { id: 'emerald', label: 'Emerald Matrix', class: 'bg-emerald-400' },
  { id: 'rose', label: 'Rose Glitch', class: 'bg-[#ff003c]' },
  { id: 'amber', label: 'Amber Signal', class: 'bg-amber-400' },
  { id: 'cyan', label: 'Cyan Core', class: 'bg-cyan-300' },
];

const FONTS = ['Inter', 'Merriweather', 'Playfair Display', 'Roboto Mono', 'Open Sans', 'Orbitron', 'Cinzel', 'Source Code Pro', 'Crimson Text'];
const LANGUAGES = ['Original', 'Arabic', 'Chinese (Simplified)', 'Chinese (Traditional)', 'Dutch', 'English', 'French', 'German', 'Hindi', 'Indonesian', 'Italian', 'Japanese', 'Korean', 'Polish', 'Portuguese', 'Russian', 'Spanish', 'Swedish', 'Thai', 'Turkish', 'Vietnamese'];

export const SettingsModal: React.FC<Props> = ({ isOpen, onClose, settings, onUpdate }) => {
  if (!isOpen) return null;

  const handleChange = <K extends keyof AppSettings>(key: K, value: AppSettings[K]) => {
    onUpdate({ ...settings, [key]: value });
  };

  return (
    <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm animate-fade-in font-sans">
        <div className="bg-[#050505] border border-zinc-800 rounded-lg shadow-[0_0_50px_rgba(0,0,0,0.9)] w-full max-w-lg relative overflow-hidden flex flex-col max-h-[90vh]">
            <div className="p-4 border-b border-zinc-900 flex items-center justify-between bg-zinc-900/50">
                <div className="flex items-center gap-2 text-[#00f3ff]">
                    <SettingsIcon size={18} />
                    <span className="text-xs font-bold font-tech uppercase tracking-widest">System_Configuration</span>
                </div>
                <button onClick={onClose} className="text-zinc-500 hover:text-white transition-colors"><X size={18} /></button>
            </div>

            <div className="p-6 space-y-8 overflow-y-auto custom-scrollbar">
                {/* Language Section */}
                <div className="space-y-3">
                    <div className="flex items-center gap-2 text-zinc-400 text-xs font-mono uppercase tracking-wider">
                        <Globe size={14} />
                        <span>Target Translation Protocol</span>
                    </div>
                    <select 
                        value={settings.targetLanguage}
                        onChange={(e) => handleChange('targetLanguage', e.target.value)}
                        className="w-full bg-[#0a0a0c] border border-zinc-800 rounded p-2 text-sm text-zinc-300 focus:border-[#00f3ff] outline-none font-sans"
                    >
                        {LANGUAGES.map(lang => (
                            <option key={lang} value={lang}>{lang}</option>
                        ))}
                    </select>
                </div>

                {/* Typography Section */}
                <div className="space-y-6 border-t border-zinc-900 pt-6">
                    <div className="flex items-center gap-2 text-zinc-400 text-xs font-mono uppercase tracking-wider mb-4">
                        <Type size={14} />
                        <span>Visual Rendering</span>
                    </div>

                    <div className="grid grid-cols-2 gap-4">
                        <div className="space-y-2">
                             <label className="text-[10px] text-zinc-600 uppercase font-bold">Font Family</label>
                             <select 
                                value={settings.font}
                                onChange={(e) => handleChange('font', e.target.value as any)}
                                className="w-[120px] bg-[#0a0a0c] border border-zinc-800 rounded p-2 text-sm text-zinc-300 focus:border-[#00f3ff] outline-none"
                             >
                                 {FONTS.map(f => <option key={f} value={f}>{f}</option>)}
                             </select>
                        </div>
                        <div className="space-y-2">
                             <label className="text-[10px] text-zinc-600 uppercase font-bold">Text Scale</label>
                             <select 
                                value={settings.textSize}
                                onChange={(e) => handleChange('textSize', e.target.value as any)}
                                className="w-[120px] bg-[#0a0a0c] border border-zinc-800 rounded p-2 text-sm text-zinc-300 focus:border-[#00f3ff] outline-none"
                             >
                                 <option value="sm">Small</option>
                                 <option value="base">Normal</option>
                                 <option value="lg">Large</option>
                                 <option value="xl">Extra Large</option>
                             </select>
                        </div>
                        <div className="space-y-2">
                             <label className="text-[10px] text-zinc-600 uppercase font-bold flex items-center gap-1"><AlignJustify size={10}/> Line Height</label>
                             <select 
                                value={settings.lineHeight}
                                onChange={(e) => handleChange('lineHeight', e.target.value as any)}
                                className="w-[120px] bg-[#0a0a0c] border border-zinc-800 rounded p-2 text-sm text-zinc-300 focus:border-[#00f3ff] outline-none"
                             >
                                 <option value="tight">Tight</option>
                                 <option value="normal">Normal</option>
                                 <option value="relaxed">Relaxed</option>
                                 <option value="loose">Loose</option>
                             </select>
                        </div>
                         <div className="space-y-2">
                             <label className="text-[10px] text-zinc-600 uppercase font-bold flex items-center gap-1"><MoveHorizontal size={10}/> Spacing</label>
                             <select 
                                value={settings.letterSpacing}
                                onChange={(e) => handleChange('letterSpacing', e.target.value as any)}
                                className="w-[120px] bg-[#0a0a0c] border border-zinc-800 rounded p-2 text-sm text-zinc-300 focus:border-[#00f3ff] outline-none"
                             >
                                 <option value="tighter">Tight</option>
                                 <option value="normal">Normal</option>
                                 <option value="wide">Wide</option>
                                 <option value="wider">Wider</option>
                             </select>
                        </div>
                    </div>
                </div>

                 {/* Highlight Color Section */}
                 <div className="space-y-3 border-t border-zinc-900 pt-6">
                    <div className="flex items-center gap-2 text-zinc-400 text-xs font-mono uppercase tracking-wider">
                        <Highlighter size={14} />
                        <span>Highlighter Frequency</span>
                    </div>
                    <div className="flex items-center gap-3">
                        {COLORS.map(color => (
                            <button
                                key={color.id}
                                onClick={() => handleChange('highlightColor', color.id)}
                                className={`w-8 h-8 rounded-full border-2 transition-all ${settings.highlightColor === color.id ? 'border-white scale-110 shadow-[0_0_10px_rgba(255,255,255,0.5)]' : 'border-transparent opacity-50 hover:opacity-100'} ${color.class}`}
                                title={color.label}
                            />
                        ))}
                    </div>
                </div>
            </div>

            <div className="p-4 border-t border-zinc-900 bg-zinc-900/50 flex justify-end">
                <button onClick={onClose} className="px-6 py-2 bg-[#00f3ff] hover:bg-[#00c2cc] text-black font-bold text-xs uppercase tracking-widest rounded-sm transition-colors">
                    Confirm_Changes
                </button>
            </div>
        </div>
    </div>
  );
};
